/**
 * A rule for testing cascading auto-corrections. This rule demonstrates the scenario where
 * initial corrections create new auto-correctable errors that need to be fixed in subsequent rounds.
 */
private class CascadingAutoCorrectRule : Rule(
    ruleId = RuleId("test:cascading-autocorrect"),
    about = About(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == REGULAR_STRING_PART) {
            when (node.text) {
                "step1" -> {
                    emit(node.startOffset, "Step 1 error - can be auto-corrected", true)
                    if (autoCorrect) {
                        (node as LeafElement).rawReplaceWithText("step2")
                    }
                }
                "step2" -> {
                    emit(node.startOffset, "Step 2 error - can be auto-corrected", true)
                    if (autoCorrect) {
                        (node as LeafElement).rawReplaceWithText("step3")
                    }
                }
                "step3" -> {
                    emit(node.startOffset, "Step 3 error - cannot be auto-corrected", false)
                }
            }
        }
    }

    companion object {
        const val INITIAL_CODE = """val test = "step1""""
        const val EXPECTED_FINAL_CODE = """val test = "step3""""
    }
}

/**
 * A rule for testing that infinite loops are prevented. This rule always creates new auto-correctable
 * errors, but the format function should stop after the maximum number of rounds.
 */
private class InfiniteLoopAutoCorrectRule : Rule(
    ruleId = RuleId("test:infinite-loop"),
    about = About(),
) {
    private var roundCounter = 0

    override fun beforeFirstNode(editorConfig: EditorConfig) {
        roundCounter++
    }

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == REGULAR_STRING_PART) {
            // Always create an auto-correctable error to test the maximum rounds limit
            emit(node.startOffset, "Round $roundCounter - can be auto-corrected", true)
            if (autoCorrect) {
                // Make a small change that doesn't actually fix the "issue"
                (node as LeafElement).rawReplaceWithText("$roundCounter")
            }
        }
    }
}"}

