import com.pinterest.ktlint.rule.engine.api.KtLintRuleEngine
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement

// Test rule that creates cascading auto-correctable errors
class TestCascadingRule : Rule(
    ruleId = RuleId("test:cascading"),
    about = About()
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
    ) {
        if (node.elementType.toString() == "REGULAR_STRING_PART") {
            when (node.text) {
                "step1" -> {
                    emit(node.startOffset, "Step 1 - auto-correctable", true)
                    if (autoCorrect) {
                        (node as LeafElement).rawReplaceWithText("step2")
                    }
                }
                "step2" -> {
                    emit(node.startOffset, "Step 2 - auto-correctable", true) 
                    if (autoCorrect) {
                        (node as LeafElement).rawReplaceWithText("step3")
                    }
                }
                "step3" -> {
                    emit(node.startOffset, "Step 3 - final error", false)
                }
            }
        }
    }
}

fun main() {
    val engine = KtLintRuleEngine(
        ruleProviders = setOf(RuleProvider { TestCascadingRule() })
    )

    val originalCode = """val test = "step1""""
    val expectedFinalCode = """val test = "step3""""

    println("Original code: $originalCode")

    var errorCount = 0
    val formattedCode = engine.format(Code.fromSnippet(originalCode)) { error, corrected ->
        errorCount++
        println("Error: ${error.detail} (corrected: $corrected)")
    }

